import { forwardRef, useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";
import style from "../style/Add.module.css";
import InputMonto from "./InputMonto";
import { movimientoService } from "../api";
import { CURRENCY_OPTIONS, normalizeCurrency } from "../utils/finance";

function Add({ onMovementAdded, movementToEdit, only, defaultCurrency = "ARS" }) {
  const navigate = useNavigate();
  const isEditing = !!movementToEdit;

  const [ingresoMonto, setIngresoMonto] = useState("");
  const [egresoMonto, setEgresoMonto] = useState("");
  const [categoriaIngreso, setCategoriaIngreso] = useState("");
  const [categoriaEgreso, setCategoriaEgreso] = useState("");
  const [detalleIngreso, setDetalleIngreso] = useState("");
  const [detalleEgreso, setDetalleEgreso] = useState("");
  const [selectedDateIngreso, setSelectedDateIngreso] = useState(new Date());
  const [selectedDateEgreso, setSelectedDateEgreso] = useState(new Date());
  const [monedaIngreso, setMonedaIngreso] = useState(
    normalizeCurrency(defaultCurrency)
  );
  const [monedaEgreso, setMonedaEgreso] = useState(
    normalizeCurrency(defaultCurrency)
  );
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const resetIngreso = useCallback(() => {
    setIngresoMonto("");
    setCategoriaIngreso("");
    setDetalleIngreso("");
    setSelectedDateIngreso(new Date());
    setMonedaIngreso(normalizeCurrency(defaultCurrency));
  }, [defaultCurrency]);

  const resetEgreso = useCallback(() => {
    setEgresoMonto("");
    setCategoriaEgreso("");
    setDetalleEgreso("");
    setSelectedDateEgreso(new Date());
    setMonedaEgreso(normalizeCurrency(defaultCurrency));
  }, [defaultCurrency]);

  useEffect(() => {
    if (isEditing) {
      const fechaUTC = new Date(movementToEdit.fecha);
      fechaUTC.setMinutes(fechaUTC.getMinutes() + fechaUTC.getTimezoneOffset());

      if (movementToEdit.tipo === "ingreso") {
        setIngresoMonto(String(movementToEdit.monto ?? ""));
        setCategoriaIngreso(movementToEdit.categoria || "");
        setDetalleIngreso(movementToEdit.detalle || "");
        setSelectedDateIngreso(fechaUTC);
        setMonedaIngreso(normalizeCurrency(movementToEdit.moneda));
        resetEgreso();
      } else {
        setEgresoMonto(String(movementToEdit.monto ?? ""));
        setCategoriaEgreso(movementToEdit.categoria || "");
        setDetalleEgreso(movementToEdit.detalle || "");
        setSelectedDateEgreso(fechaUTC);
        setMonedaEgreso(normalizeCurrency(movementToEdit.moneda));
        resetIngreso();
      }

      return;
    }

    resetIngreso();
    resetEgreso();
  }, [movementToEdit, isEditing, resetEgreso, resetIngreso]);

  const handleSubmit = async (event, tipo) => {
    event.preventDefault();
    setError("");
    setLoading(true);

    const isIngreso = tipo === "ingreso";
    const monto = isIngreso ? ingresoMonto : egresoMonto;
    const categoria = isIngreso ? categoriaIngreso : categoriaEgreso;
    const detalle = isIngreso ? detalleIngreso : detalleEgreso;
    const selectedDate = isIngreso ? selectedDateIngreso : selectedDateEgreso;
    const moneda = isIngreso ? monedaIngreso : monedaEgreso;

    if (!monto || Number.isNaN(parseFloat(monto)) || parseFloat(monto) <= 0) {
      setError("Ingresa un monto valido.");
      setLoading(false);
      return;
    }

    if (!categoria.trim()) {
      setError("La categoria es obligatoria.");
      setLoading(false);
      return;
    }

    const fechaLocal = new Date(selectedDate);
    fechaLocal.setMinutes(fechaLocal.getMinutes() - fechaLocal.getTimezoneOffset());
    const fechaFormateada = fechaLocal.toISOString().slice(0, 10);

    const dataToSend = {
      tipo: isEditing ? movementToEdit.tipo : tipo,
      monto: parseFloat(monto),
      categoria: categoria.trim(),
      fecha: fechaFormateada,
      detalle: detalle.trim(),
      moneda: normalizeCurrency(moneda),
    };

    try {
      let savedMovement;

      if (isEditing) {
        const response = await movimientoService.update(movementToEdit._id, dataToSend);
        savedMovement = response.data;
      } else {
        const response = await movimientoService.create(dataToSend);
        savedMovement = response.data;

        if (isIngreso) {
          resetIngreso();
        } else {
          resetEgreso();
        }
      }

      onMovementAdded?.(savedMovement);

      if (!only) {
        navigate("/");
      }
    } catch (err) {
      setError(err.response?.data?.error || "Error al guardar el movimiento");
    } finally {
      setLoading(false);
    }
  };

  const CustomDateInput = forwardRef(({ value, onClick }, ref) => (
    <input
      className={style.datePicker}
      onClick={onClick}
      ref={ref}
      value={value}
      readOnly
    />
  ));

  CustomDateInput.displayName = "CustomDateInput";

  const renderCurrencySwitch = (value, onChange) => (
    <div className={style.currencySwitch}>
      {CURRENCY_OPTIONS.map((option) => (
        <button
          key={option.value}
          type="button"
          className={`${style.currencyOption} ${
            value === option.value ? style.currencyOptionActive : ""
          }`}
          onClick={() => onChange(option.value)}
        >
          {option.codeLabel}
        </button>
      ))}
    </div>
  );

  const renderForm = ({
    tipo,
    title,
    description,
    monto,
    setMonto,
    categoria,
    setCategoria,
    detalle,
    setDetalle,
    selectedDate,
    setSelectedDate,
    moneda,
    setMoneda,
    cardClassName,
    disabled,
  }) => (
    <form className={cardClassName} onSubmit={(event) => handleSubmit(event, tipo)}>
      <div className={style.formHeader}>
        <div>
          <p className={style.formEyebrow}>{title}</p>
          <h3>{description}</h3>
        </div>
        {renderCurrencySwitch(moneda, setMoneda)}
      </div>

      <InputMonto
        className={style.inputMonto}
        value={monto}
        onChange={setMonto}
        placeholder={`Monto en ${moneda === "USD" ? "USD" : "ARS"}`}
        disabled={disabled}
      />

      <div className={style.containerBtn}>
        <input
          name={`categoria-${tipo}`}
          className={style.btn}
          placeholder="Categoria"
          value={categoria}
          onChange={(event) => setCategoria(event.target.value)}
          required
          disabled={disabled}
        />
        <DatePicker
          selected={selectedDate}
          onChange={setSelectedDate}
          dateFormat="dd/MM/yyyy"
          customInput={<CustomDateInput />}
          wrapperClassName={style.datePickerWrapper}
          disabled={disabled}
        />
      </div>

      <div className={style.containerDetalle}>
        <input
          name={`detalle-${tipo}`}
          className={style.detalle}
          placeholder="Detalle o referencia"
          value={detalle}
          onChange={(event) => setDetalle(event.target.value)}
          disabled={disabled}
        />
        <button className={style.buttonSend} type="submit" disabled={loading || disabled}>
          {isEditing ? "Guardar cambios" : `Guardar ${tipo}`}
        </button>
      </div>
    </form>
  );

  return (
    <div className={style.container}>
      {loading && <div className={style.spinner}></div>}

      <div className={style.titleRow}>
        <div>
          <p className={style.kicker}>Movimientos</p>
          <h2 className={style.title}>
            {isEditing ? "Editar movimiento" : "Cargar ingresos y egresos"}
          </h2>
        </div>
        <p className={style.subtitle}>
          Cada movimiento puede guardarse en pesos o dolares sin mezclar cajas.
        </p>
      </div>

      <div className={style.containerAllForm}>
        {(!only || only === "ingreso") &&
          (!isEditing || movementToEdit.tipo === "ingreso") &&
          renderForm({
            tipo: "ingreso",
            title: "Ingreso",
            description: "Registra cobros, ventas o entradas de efectivo.",
            monto: ingresoMonto,
            setMonto: setIngresoMonto,
            categoria: categoriaIngreso,
            setCategoria: setCategoriaIngreso,
            detalle: detalleIngreso,
            setDetalle: setDetalleIngreso,
            selectedDate: selectedDateIngreso,
            setSelectedDate: setSelectedDateIngreso,
            moneda: monedaIngreso,
            setMoneda: setMonedaIngreso,
            cardClassName: style.formone,
            disabled: isEditing && movementToEdit.tipo === "egreso",
          })}

        {(!only || only === "egreso") &&
          (!isEditing || movementToEdit.tipo === "egreso") &&
          renderForm({
            tipo: "egreso",
            title: "Egreso",
            description: "Guarda pagos, compras o gastos operativos.",
            monto: egresoMonto,
            setMonto: setEgresoMonto,
            categoria: categoriaEgreso,
            setCategoria: setCategoriaEgreso,
            detalle: detalleEgreso,
            setDetalle: setDetalleEgreso,
            selectedDate: selectedDateEgreso,
            setSelectedDate: setSelectedDateEgreso,
            moneda: monedaEgreso,
            setMoneda: setMonedaEgreso,
            cardClassName: style.formtwo,
            disabled: isEditing && movementToEdit.tipo === "ingreso",
          })}
      </div>

      {isEditing && (
        <div className={style.cancelContainer}>
          <button
            className={style.cancelButton}
            type="button"
            onClick={() => {
              onMovementAdded?.();
              navigate("/");
            }}
          >
            Cancelar edicion
          </button>
        </div>
      )}

      {error && <p className={style.errorText}>{error}</p>}
    </div>
  );
}

export default Add;
